// App.js
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/layout/Sidebar';
import DashboardContent from './components/layout/DashboardContent';
import AccessManagementContent from './components/layout/AccessManagementContent';
import AddAccessContent from './components/layout/AddAccessContent'; // Nouveau composant
import PlateformeManagementContent from './components/layout/PlateformeManagementContent';
import LoginForm from './components/layout/LoginForm';

export default function App() {
  return (
    <Router>
      <div className="flex min-h-screen bg-gray-50">
        <Sidebar />

        <div className="flex-1">
          <Routes>
            <Route path="/login" element={<LoginForm />} />
            <Route path="/" element={<Navigate to="/dashboard" replace />} />
            <Route path="/dashboard" element={<DashboardContent />} />
            <Route path="/access" element={<AccessManagementContent />} />
            <Route path="/access/add" element={<AddAccessContent />} />
            <Route path="/access/:accessId" element={<AddAccessContent />} /> {/* ✅ Pour View & Edit */}
            <Route path="/setting" element={<PlateformeManagementContent />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}
